use distributed_inference::leech_visual_sieve::{
    characterize_leech_visual_image, leech_visual_key, LeechVisualSieveConfig,
    LeechVisualSieveReport, LEECH_VISUAL_DIM,
};
use serde::Serialize;
use std::path::PathBuf;
use std::time::Instant;

const CERTIFICATE_VERSION: &str = "gnosis.leech-visual-sieve.shell-cache.v1";

#[derive(Clone, Debug)]
struct Config {
    width: usize,
    height: usize,
    stride: usize,
    repeats: usize,
    keys: usize,
    output: Option<PathBuf>,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            width: 256,
            height: 256,
            stride: 32,
            repeats: 3,
            keys: 512,
            output: None,
        }
    }
}

fn parse_args() -> Config {
    let mut cfg = Config::default();
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        let Some(value) = args.next() else {
            panic!("missing value for {arg}");
        };
        match arg.as_str() {
            "--width" => cfg.width = parse_usize(&arg, &value, 1),
            "--height" => cfg.height = parse_usize(&arg, &value, 1),
            "--stride" => cfg.stride = parse_usize(&arg, &value, 1),
            "--repeats" => cfg.repeats = parse_usize(&arg, &value, 1),
            "--keys" => cfg.keys = parse_usize(&arg, &value, 1),
            "--output" => cfg.output = Some(PathBuf::from(value)),
            _ => panic!("unknown argument: {arg}"),
        }
    }
    cfg
}

fn parse_usize(name: &str, value: &str, min: usize) -> usize {
    value
        .parse::<usize>()
        .ok()
        .filter(|v| *v >= min)
        .unwrap_or_else(|| panic!("{name} must be an integer >= {min}"))
}

fn synthetic_rgb(width: usize, height: usize) -> Vec<f32> {
    let mut rgb = vec![0.0_f32; width * height * 3];
    for y in 0..height {
        for x in 0..width {
            let base = (y * width + x) * 3;
            let fx = x as f32;
            let fy = y as f32;
            let v = 0.5
                + 0.22 * (fx * 0.031).sin()
                + 0.17 * (fy * 0.047).cos()
                + 0.11 * ((fx - fy) * 0.019).sin();
            let v = v.clamp(0.0, 1.0);
            rgb[base] = v;
            rgb[base + 1] = (0.76 * v + 0.12 * (fx * 0.013).cos()).clamp(0.0, 1.0);
            rgb[base + 2] = (0.63 * v + 0.18 * (fy * 0.017).sin()).clamp(0.0, 1.0);
        }
    }
    rgb
}

fn synthetic_features(keys: usize) -> Vec<[f32; LEECH_VISUAL_DIM]> {
    let mut out = Vec::with_capacity(keys);
    for k in 0..keys {
        let mut feature = [0.0_f32; LEECH_VISUAL_DIM];
        for (i, x) in feature.iter_mut().enumerate() {
            let t = (k as f32 + 1.0) * (i as f32 + 3.0);
            *x = 0.13 * (t * 0.017).sin() + 0.07 * (t * 0.031).cos();
        }
        out.push(feature);
    }
    out
}

fn median(mut values: Vec<f64>) -> f64 {
    values.sort_by(|a, b| a.total_cmp(b));
    let mid = values.len() / 2;
    if values.len().is_multiple_of(2) {
        0.5 * (values[mid - 1] + values[mid])
    } else {
        values[mid]
    }
}

#[derive(Serialize)]
struct BenchPayload {
    #[serde(rename = "certificateVersion")]
    certificate_version: &'static str,
    tool: &'static str,
    scope: &'static str,
    config: BenchConfigPayload,
    timing: BenchTimingPayload,
    occupancy: BenchOccupancyPayload,
    #[serde(rename = "shellCache")]
    shell_cache: ShellCachePayload,
    #[serde(rename = "cacheAdmission")]
    cache_admission: CacheAdmissionPayload,
    #[serde(rename = "proof_spine")]
    proof_spine: Vec<ProofSpineEntry>,
}

#[derive(Serialize)]
struct BenchConfigPayload {
    width: usize,
    height: usize,
    stride: usize,
    repeats: usize,
    direct_keys: usize,
    sample_count: usize,
}

#[derive(Serialize)]
struct BenchTimingPayload {
    image_median_ms: f64,
    image_per_sample_us: f64,
    image_samples_ms: Vec<f64>,
    key_median_ms: f64,
    key_per_key_us: f64,
    key_samples_ms: Vec<f64>,
}

#[derive(Serialize)]
struct BenchOccupancyPayload {
    origin_keys: usize,
    shell_keys: usize,
    unique_keys: usize,
    mean_energy_sq: f32,
    mean_shell_margin: f32,
}

#[derive(Serialize)]
struct ShellCachePayload {
    addressable_shell_keys: usize,
    hits: usize,
    hit_rate: f64,
    nodes_saved: usize,
    address_variation: usize,
    compressed_address_variation: usize,
    vector_variation: u32,
    compressed_vector_variation: u32,
}

#[derive(Serialize)]
struct CacheAdmissionPayload {
    candidate: bool,
    policy: &'static str,
    reason: &'static str,
}

#[derive(Serialize)]
struct ProofSpineEntry {
    key: &'static str,
    module: &'static str,
}

fn build_payload(
    cfg: &Config,
    sample_count: usize,
    image_ms: Vec<f64>,
    key_ms: Vec<f64>,
    report: LeechVisualSieveReport,
    shell_cache_hit_rate: f64,
) -> BenchPayload {
    let cache_candidate = report.addressable_shell_keys > 0 && report.shell_cache_hits > 0;
    BenchPayload {
        certificate_version: CERTIFICATE_VERSION,
        tool: "bench-leech-visual-sieve",
        scope: "synthetic 24-D Leech visual keys; Golay-sign shell cache telemetry",
        config: BenchConfigPayload {
            width: cfg.width,
            height: cfg.height,
            stride: cfg.stride,
            repeats: cfg.repeats,
            direct_keys: cfg.keys,
            sample_count,
        },
        timing: BenchTimingPayload {
            image_median_ms: median(image_ms.clone()),
            image_per_sample_us: median(image_ms.clone()) * 1000.0 / sample_count.max(1) as f64,
            image_samples_ms: image_ms,
            key_median_ms: median(key_ms.clone()),
            key_per_key_us: median(key_ms.clone()) * 1000.0 / cfg.keys.max(1) as f64,
            key_samples_ms: key_ms,
        },
        occupancy: BenchOccupancyPayload {
            origin_keys: report.origin_keys,
            shell_keys: report.shell_keys,
            unique_keys: report.unique_keys,
            mean_energy_sq: report.mean_energy_sq,
            mean_shell_margin: report.mean_shell_margin,
        },
        shell_cache: ShellCachePayload {
            addressable_shell_keys: report.addressable_shell_keys,
            hits: report.shell_cache_hits,
            hit_rate: shell_cache_hit_rate,
            nodes_saved: report.shell_nodes_saved,
            address_variation: report.shell_address_variation,
            compressed_address_variation: report.shell_compressed_address_variation,
            vector_variation: report.shell_vector_variation,
            compressed_vector_variation: report.shell_compressed_vector_variation,
        },
        cache_admission: CacheAdmissionPayload {
            candidate: cache_candidate,
            policy: "addressable_shell_keys > 0 && shell_cache_hits > 0",
            reason: if cache_candidate {
                "repeated Golay-sign shell keys observed; resident shell cache promotion is worth measuring"
            } else {
                "no repeated addressable Golay-sign shell keys observed in this sample"
            },
        },
        proof_spine: vec![
            ProofSpineEntry {
                key: "leech-surface",
                module: "Gnosis.LeechNearestPoint",
            },
            ProofSpineEntry {
                key: "aizawa-leech-cache",
                module: "Gnosis.AizawaLeechCompletion",
            },
        ],
    }
}

fn write_payload(path: &PathBuf, payload: &BenchPayload) {
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).expect("create output directory");
    }
    let json = serde_json::to_string_pretty(payload).expect("serialize benchmark payload");
    std::fs::write(path, format!("{json}\n")).expect("write benchmark payload");
}

fn main() {
    let cfg = parse_args();
    let sieve = LeechVisualSieveConfig::default();
    let rgb = synthetic_rgb(cfg.width, cfg.height);
    let features = synthetic_features(cfg.keys);

    let sample_count = cfg.width.div_ceil(cfg.stride) * cfg.height.div_ceil(cfg.stride);
    let mut image_ms = Vec::with_capacity(cfg.repeats);
    let mut key_ms = Vec::with_capacity(cfg.repeats);
    let mut last_hash = 0_u64;
    let mut last_report: Option<LeechVisualSieveReport> = None;

    for _ in 0..cfg.repeats {
        let t0 = Instant::now();
        let report =
            characterize_leech_visual_image(&rgb, cfg.width, cfg.height, cfg.stride, &sieve);
        image_ms.push(t0.elapsed().as_secs_f64() * 1000.0);
        last_report = Some(report);

        let t1 = Instant::now();
        for feature in &features {
            last_hash ^= leech_visual_key(feature, &sieve).hash;
        }
        key_ms.push(t1.elapsed().as_secs_f64() * 1000.0);
    }

    let image_median = median(image_ms.clone());
    let key_median = median(key_ms.clone());
    let per_sample_us = image_median * 1000.0 / sample_count.max(1) as f64;
    let per_key_us = key_median * 1000.0 / cfg.keys.max(1) as f64;
    let report = last_report.expect("at least one benchmark repeat");
    let shell_cache_hit_rate = if report.addressable_shell_keys == 0 {
        0.0
    } else {
        report.shell_cache_hits as f64 / report.addressable_shell_keys as f64
    };

    println!("Leech visual sieve microbench");
    println!(
        "  image: {}x{}, stride={}, samples={}, repeats={}",
        cfg.width, cfg.height, cfg.stride, sample_count, cfg.repeats
    );
    println!("  direct keys: {}", cfg.keys);
    println!(
        "  image median: {:.3}ms ({:.3}us/sample), samples={:?}",
        image_median, per_sample_us, image_ms
    );
    println!(
        "  key median:   {:.3}ms ({:.3}us/key), samples={:?}",
        key_median, per_key_us, key_ms
    );
    println!(
        "  occupancy: origin={} shell={} unique={} mean_energy={:.4} mean_shell_margin={:.4}",
        report.origin_keys,
        report.shell_keys,
        report.unique_keys,
        report.mean_energy_sq,
        report.mean_shell_margin
    );
    println!(
        "  shell cache: addressable={} hits={} hit_rate={:.2}% nodes_saved={}",
        report.addressable_shell_keys,
        report.shell_cache_hits,
        100.0 * shell_cache_hit_rate,
        report.shell_nodes_saved
    );
    println!(
        "  shell variation: address={} compressed_address={} vector={} compressed_vector={}",
        report.shell_address_variation,
        report.shell_compressed_address_variation,
        report.shell_vector_variation,
        report.shell_compressed_vector_variation
    );
    println!(
        "  guard: unique_keys={} hash_xor={}",
        report.unique_keys, last_hash
    );

    if let Some(output) = &cfg.output {
        let payload = build_payload(
            &cfg,
            sample_count,
            image_ms,
            key_ms,
            report,
            shell_cache_hit_rate,
        );
        write_payload(output, &payload);
        println!("  wrote: {}", output.display());
    }
}
